// pages/index.tsx
import React from 'react';
import { GetServerSideProps } from 'next';
import { getFirebaseAdminEnvForDiagnostics } from '../lib/firebaseAdmin'; // <-- Импортируем диагностическую функцию

interface DiagnosticsPageProps {
  env: {
    projectId: string;
    clientEmail: string;
    privateKeyBase64Status: string;
    oldPrivateKeyStatus: string;
  };
}

// Этот компонент временно заменит вашу главную страницу для вывода диагностики.
export default function DiagnosticsPage({ env }: DiagnosticsPageProps) {
  return (
    <div style={{ padding: '2rem', fontFamily: 'monospace', lineHeight: '1.6' }}>
      <h1>Server Environment Diagnostics</h1>
      <p>This page shows what environment variables the server is actually seeing.</p>
      <hr style={{ margin: '1rem 0' }} />
      <div>
        <strong>FIREBASE_PROJECT_ID:</strong> {env.projectId}
      </div>
      <div>
        <strong>FIREBASE_CLIENT_EMAIL:</strong> {env.clientEmail}
      </div>
      <div>
        <strong>FIREBASE_PRIVATE_KEY_BASE64:</strong> {env.privateKeyBase64Status}
      </div>
      <div>
        <strong>(Old) FIREBASE_PRIVATE_KEY:</strong> {env.oldPrivateKeyStatus}
      </div>
      <hr style={{ margin: '1rem 0' }} />
      <h2>Next Steps:</h2>
      <p>
        If any of these say "!!! MISSING !!!", please double-check your `.env.local` file. 
        Ensure it is in the root directory and that the variable names match exactly.
      </p>
    </div>
  );
}

export const getServerSideProps: GetServerSideProps = async () => {
  const env = getFirebaseAdminEnvForDiagnostics();
  return {
    props: {
      env,
    },
  };
};
